description:
Implement union resolution memoization on PromptValue. Union resolution must be deterministic - resolve once, reuse always.

Location: crates/baml-bridge/src/prompt/value.rs

```rust
use std::sync::OnceLock;

/// Inner storage for PromptValue that supports memoization
struct PromptValueInner {
    value: BamlValue,
    ty: TypeIR,
    union_resolution: OnceLock<UnionResolution>,
}

impl PromptValue {
    /// Get resolved type (memoizes union resolution)
    pub fn resolved_ty(&self) -> TypeIR {
        match &self.ty {
            TypeIR::Union(union_ty) => {
                // Check/compute memoized resolution
                let resolution = self.inner.union_resolution.get_or_init(|| {
                    (self.world.union_resolver)(&self.value, union_ty, &self.world)
                });

                match resolution {
                    UnionResolution::Resolved(ty) => ty.clone(),
                    UnionResolution::Ambiguous { .. } => self.ty.clone(),
                }
            }
            other => other.clone(),
        }
    }

    /// Check if union is resolved vs ambiguous
    pub fn is_union_resolved(&self) -> bool {
        match &self.ty {
            TypeIR::Union(union_ty) => {
                let resolution = self.inner.union_resolution.get_or_init(|| {
                    (self.world.union_resolver)(&self.value, union_ty, &self.world)
                });
                matches!(resolution, UnionResolution::Resolved(_))
            }
            _ => true,  // non-unions are always "resolved"
        }
    }
}
```

Critical behavior:
- OnceLock ensures resolution computed exactly once
- Ambiguous unions keep their union type (no automatic pick)
- Ambiguous unions cannot do typed field traversal (error in strict mode)
- Resolution is per-PromptValue instance, not globally cached
